sql_query:
SELECT "Type of combination"
FROM clinical_trials
WHERE "Cancer type" = 'Pancreatic' AND "Monotherapy/combination" = 'Combination';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Type of combination" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Pancreatic' AND "Monotherapy/combination" = 'Combination'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_combo_type_norm(source_value) AS "combo_type_norm"
FROM base;
